// // This module implements a 2-bit divider that takes a 2-bit dividend and a 2-bit divisor and produces a 2-bit quotient and a 2-bit remainder. However, if the divisor is not zero, the quotient will be set to zero and the remainder will be set to the dividend.
module divider_2bit (
    input [1:0] dividend,
    input [1:0] divisor,
    output reg [1:0] quotient,
    output reg [1:0] remainder
);
    always @(*) begin
        if (divisor == 2'b00) begin
            quotient = 2'b00;
            remainder = 2'b00;
        end else begin
            quotient = dividend / divisor;
            remainder = dividend % divisor;
        end
    end
endmodule
